mapper.update:
UPDATE  TB_PROGRM_CHANGE_DTLS
   SET  RQESTER_ID = #{rqesterPersonId}
      , CHANGE_REQUST_CN = #changerqesterCn:CLOB#
      , REQUST_PROCESS_CN = #rqesterProcessCn:CLOB#
      , REQUST_DE = TO_DATE(#{rqesterDe}, 'yyyy-mm-dd')
      , REQUST_SJ = #{rqesterSj}
 WHERE  PROGRM_FILE_NM = #{progrmFileNm}
   AND  REQUST_NO = #{rqesterNo}

mapper.delete:
DELETE
  FROM  TB_PROGRM_CHANGE_DTLS
 WHERE  PROGRM_FILE_NM = #{progrmFileNm}
   AND  REQUST_NO = #{rqesterNo}

mapper.update:
UPDATE  TB_PROGRM_CHANGE_DTLS
   SET  CHANGE_REQUST_CN = #changerqesterCn:CLOB#
      , REQUST_PROCESS_CN = #rqesterProcessCn:CLOB#
      , OPETR_ID = #{opetrId}
      , PROCESS_STTUS_CODE = #{processSttus}
      , PROCESS_DE = TO_DATE(#{processDe}, 'yyyy-mm-dd')
 WHERE  PROGRM_FILE_NM = #{progrmFileNm}
   AND  REQUST_NO = #{rqesterNo}

mapper.select:
SELECT PROGRM_FILE_NM AS "PROGRM_FILE_NM" , REQUST_NO AS "REQUST_NO" , RQESTER_ID AS "RQESTER_ID" , CHANGE_REQUST_CN AS "CHANGE_REQUST_CN" , REQUST_PROCESS_CN AS "REQUST_PROCESS_CN" , OPETR_ID AS "OPETR_ID" , TRIM(PROCESS_STTUS_CODE) AS "PROCESS_STTUS_CODE" , TO_CHAR(PROCESS_DE, 'YYYY-MM-DD') AS "PROCESS_DE" , TO_CHAR(REQUST_DE, 'YYYY-MM-DD') AS "REQUST_DE" , REQUST_SJ AS "REQUST_SJ" FROM ( SELECT ROWNUM RN , TB.PROGRM_FILE_NM , TB.REQUST_NO , TB.RQESTER_ID , TB.CHANGE_REQUST_CN , TB.REQUST_PROCESS_CN , TB.OPETR_ID , TB.PROCESS_STTUS_CODE , TB.PROCESS_DE , TB.REQUST_DE , TB.REQUST_SJ FROM ( SELECT PROGRM_FILE_NM , REQUST_NO , RQESTER_ID , CHANGE_REQUST_CN , REQUST_PROCESS_CN , OPETR_ID , PROCESS_STTUS_CODE , PROCESS_DE , REQUST_DE , REQUST_SJ FROM TB_PROGRM_CHANGE_DTLS WHERE 1 = 1
AND PROCESS_STTUS_CODE LIKE #{searchKeyword}
AND PROCESS_STTUS_CODE = #{searchKeyword}
AND TO_CHAR(REQUST_DE, 'YYYY-MM-DD') BETWEEN #{searchKeywordFrom} AND #{searchKeywordTo}
AND RQESTER_ID LIKE '%' || #{searchKeyword} || '%'
ORDER BY REQUST_NO ASC ) TB ) WHERE RN BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

SELECT  COUNT(REQUST_NO) AS "totcnt"
  FROM  TB_PROGRM_CHANGE_DTLS
 WHERE  1 = 1

   AND  PROCESS_STTUS_CODE LIKE #{searchKeyword}


   AND  PROCESS_STTUS_CODE = #{searchKeyword}


   AND  TO_CHAR(REQUST_DE, 'YYYY-MM-DD') BETWEEN #{searchKeywordFrom} AND #{searchKeywordTo}


   AND  RQESTER_ID LIKE '%' || #{searchKeyword} || '%'

SELECT  USER_EMAIL AS "tmp_Email"
  FROM  VW_USER_MASTER
 WHERE  USER_ID = #{rqesterPersonId}
